11	func writeTestFile(t *testing.T, dir, rel, content string) {
12		t.Helper()
13		path := filepath.Join(dir, filepath.FromSlash(rel))
14		if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
15			t.Fatal(err)
16		}
17		if err := os.WriteFile(path, []byte(content), 0644); err != nil {
18			t.Fatal(err)
19		}
20	}
