22	// TestDocAuditCommand_CleanRepoExitsZero verifies the no-issues path:
23	// success, exit code 0 (no error returned), and a short "clean" message.
24	func TestDocAuditCommand_CleanRepoExitsZero(t *testing.T) {
25		dir := t.TempDir()
26		writeTestFile(t, dir, "docs/a.md", "---\nddx:\n  id: doc.a\n---\n# A\n")
27		writeTestFile(t, dir, "docs/b.md",
28			"---\nddx:\n  id: doc.b\n  depends_on:\n    - doc.a\n---\n# B\n")
29	
30		root := NewCommandFactory(dir).NewRootCommand()
31		root.SetArgs([]string{"doc", "audit"})
32	
33		out := &bytes.Buffer{}
34		errOut := &bytes.Buffer{}
35		root.SetOut(out)
36		root.SetErr(errOut)
37	
38		if err := root.Execute(); err != nil {
39			t.Fatalf("doc audit on clean repo should succeed, got: %v", err)
40		}
41		if !strings.Contains(out.String(), "clean") {
42			t.Errorf("expected clean message, got: %q", out.String())
43		}
44	}
