46	// TestDocAuditCommand_IssuesExitOne verifies the failure path: a duplicate ID
47	// fixture must produce a grouped report and a non-zero exit via ExitError.
48	func TestDocAuditCommand_IssuesExitOne(t *testing.T) {
49		dir := t.TempDir()
50		writeTestFile(t, dir, "docs/a.md", "---\nddx:\n  id: dup.id\n---\n# A\n")
51		writeTestFile(t, dir, "docs/b.md", "---\nddx:\n  id: dup.id\n---\n# B\n")
52		writeTestFile(t, dir, "docs/c.md",
53			"---\nddx:\n  id: doc.c\n  depends_on:\n    - ghost.id\n---\n# C\n")
54	
55		root := NewCommandFactory(dir).NewRootCommand()
56		root.SetArgs([]string{"doc", "audit"})
57	
58		out := &bytes.Buffer{}
59		errOut := &bytes.Buffer{}
60		root.SetOut(out)
61		root.SetErr(errOut)
62	
63		err := root.Execute()
64		if err == nil {
65			t.Fatal("doc audit on broken repo must return error for exit 1")
66		}
67		exitErr, ok := err.(*ExitError)
68		if !ok {
69			t.Fatalf("expected *ExitError, got %T: %v", err, err)
70		}
71		if exitErr.Code != ExitCodeGeneralError {
72			t.Errorf("expected exit code %d, got %d", ExitCodeGeneralError, exitErr.Code)
73		}
74	
75		outStr := out.String()
76		if !strings.Contains(outStr, "duplicate_id") {
77			t.Errorf("expected duplicate_id group in output, got: %q", outStr)
78		}
79		if !strings.Contains(outStr, "missing_dep") {
80			t.Errorf("expected missing_dep group in output, got: %q", outStr)
81		}
82		if !strings.Contains(errOut.String(), "integrity issue") {
83			t.Errorf("expected stderr summary, got: %q", errOut.String())
84		}
85	}
